// ────────────────────────────────────────────
// COMBINE AND WRITE ALL FILES
// ────────────────────────────────────────────
const allRegions = [
  ...wineRegions.map(r => ({ ...r, cropType: "Wine" })),
  ...coffeeRegions.map(r => ({ ...r, cropType: "Coffee" })),
  ...teaRegions.map(r => ({ ...r, cropType: "Tea" })),
];

// Write data/*.json files
for (const r of allRegions) {
  const data = {
    code: r.code,
    name: r.name,
    cropType: r.cropType,
    description: r.description,
    varieties: r.varieties,
    productionVolume: r.productionVolume,
    altitude: r.altitude,
    climate: r.climate,
    flavorProfile: r.flavorProfile,
    geojson: `${r.code}.geojson`,
  };
  writeFileSync(join(DATA_DIR, `${r.code}.json`), JSON.stringify(data, null, 2) + "\n");
}

// Write geo/*.geojson files
for (const r of allRegions) {
  const features = r.polygons.map((p) => ({
    type: "Feature",
    properties: { code: r.code, name: r.name, region: p.region, country: r.country },
    geometry: { type: "Polygon", coordinates: [p.coords] },
  }));
  const geojson = { type: "FeatureCollection", features };
  writeFileSync(join(GEO_DIR, `${r.code}.geojson`), JSON.stringify(geojson) + "\n");
}

const wineCount = wineRegions.length;
const coffeeCount = coffeeRegions.length;
const teaCount = teaRegions.length;
console.log(`Generated ${allRegions.length} beverage regions (${wineCount} wine, ${coffeeCount} coffee, ${teaCount} tea) — data + geo`);
